def calculate_password_strength(password):
    strength = 0
    length = len(password)

    # Länge des Passworts
    if length >= 8:
        strength += 1
    if length >= 12:
        strength += 1
    if length >= 16:
        strength += 1

    # Großbuchstaben
    if any(c.isupper() for c in password):
        strength += 1

    # Kleinbuchstaben
    if any(c.islower() for c in password):
        strength += 1

    # Zahlen
    if any(c.isdigit() for c in password):
        strength += 1

    # Sonderzeichen
    special_chars = "!@#$%^&*()_+-=[]{}|;:,.<>?"
    if any(c in special_chars for c in password):
        strength += 1

    return strength
